#include<bits/stdc++.h>
using namespace std;
int n;
struct node
{
    int ax,ay,bx,by;
}a[5050];
int p[20010];
bool cmpx(node x,node y)
{
    return x.ax<y.ax;
}
bool cmpy(node x,node y)
{
    return x.ay<y.ay;
}
int solvex()
{
    int ans=0;
    memset(p,-1,sizeof(p));
    sort(a+1,a+1+n,cmpx);
    for(int i=1;i<=n;i++)
    {
        for(int j=a[i].ay;j<a[i].by;j++)
        {
            if(a[i].ax>p[j])
            {
                ans+=2;
            }
            if(a[i].bx>p[j])
            {
                p[j]=a[i].bx;
            }
        }
    }
    return ans;
}
int solvey()
{
    int ans=0;
    memset(p,-1,sizeof(p));
    sort(a+1,a+1+n,cmpy);
    for(int i=1;i<=n;i++)
    {
        for(int j=a[i].ax;j<a[i].bx;j++)
        {
            if(a[i].ay>p[j])
            {
                ans+=2;
            }
            if(a[i].by>p[j])
            {
                p[j]=a[i].by;
            }
        }
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d%d%d%d",&a[i].ax,&a[i].ay,&a[i].bx,&a[i].by);
        a[i].ax+=10001;
        a[i].ay+=10001;
        a[i].bx+=10001;
        a[i].by+=10001;
    }
    printf("%d",solvex()+solvey());
    return 0;
}
